'use client';

import { useForm } from 'react-hook-form';
import axios from 'axios';
import { useEffect, useState } from 'react';
import { Plus, Paperclip } from 'lucide-react';

interface User {
  _id: string;
  name: string;
  email: string;
  password: string;
}

export default function TaskForm({ onSuccess }: { onSuccess: () => void }) {
  const { register, handleSubmit, reset } = useForm();
  const [users, setUsers] = useState<User[]>([]);

  useEffect(() => {
    axios.get('/api/users').then((res) => setUsers(res.data));
  }, []);

  const onSubmit = async (data: unknown) => {
    await axios.post('/api/tasks', data);
    reset();
    onSuccess();
  };

  return (
    <form
      onSubmit={handleSubmit(onSubmit)}
      className="max-w-3xl mx-auto bg-white p-6 rounded-lg shadow space-y-6"
    >
      <h2 className="text-2xl font-bold">Create Task</h2>

      {/* Task Title */}
      <div>
        <label className="block font-medium text-gray-700 mb-1">Task Title</label>
        <input
          type="text"
          {...register('title')}
          placeholder="Enter title"
          className="w-full border rounded px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
      </div>

      {/* Description */}
      <div>
        <label className="block font-medium text-gray-700 mb-1">Description</label>
        <textarea
          {...register('description')}
          rows={4}
          placeholder="Enter task description"
          className="w-full border rounded px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
        ></textarea>
      </div>

      {/* Priority, Due Date, Assign */}
      <div className="flex flex-col md:flex-row gap-4">
        {/* Priority */}
        <div className="flex-1">
          <label className="block font-medium text-gray-700 mb-1">Priority</label>
          <select
            {...register('priority')}
            className="w-full border rounded px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="low">Low</option>
            <option value="medium">Medium</option>
            <option value="high">High</option>
          </select>
        </div>

        {/* Due Date */}
        <div className="flex-1">
          <label className="block font-medium text-gray-700 mb-1">Due Date</label>
          <input
            type="date"
            {...register('dueDate')}
            className="w-full border rounded px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>

        {/* Assign To */}
        <div className="flex-1">
          <label className="block font-medium text-gray-700 mb-1">Assign To</label>
          <select
            {...register('assignedTo')}
            className="w-full border rounded px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            {users.map((u) => (
              <option key={u._id} value={u._id}>
                {u.name}
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* TODO Checklist */}
      <div>
        <label className="block font-medium text-gray-700 mb-1">TODO Checklist</label>
        <div className="flex items-center gap-2">
          <input
            type="text"
            placeholder="Enter Task"
            className="flex-1 border rounded px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
          <button
            type="button"
            className="p-2 rounded bg-blue-500 text-white hover:bg-blue-600"
          >
            <Plus size={18} />
          </button>
        </div>
      </div>

      {/* Attachments */}
      <div>
        <label className="block font-medium text-gray-700 mb-1">Add Attachments</label>
        <div className="flex items-center gap-2">
          <input
            type="text"
            placeholder="Add File Link"
            className="flex-1 border rounded px-4 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
          <button
            type="button"
            className="p-2 rounded bg-blue-500 text-white hover:bg-blue-600"
          >
            <Paperclip size={18} />
          </button>
        </div>
      </div>

      {/* Submit */}
      <div className="pt-4">
        <button
          type="submit"
          className="w-full bg-blue-600 text-white py-2 rounded hover:bg-blue-700 font-semibold"
        >
          Create Task
        </button>
      </div>
    </form>
  );
}
